"""matplotlib.legend_handler — legend handler stubs."""


class HandlerBase:
    def __init__(self, xpad=0, ypad=0, update_func=None):
        self._xpad = xpad
        self._ypad = ypad

    def legend_artist(self, legend, orig_handle, fontsize, handlebox):
        return None

    def create_artists(self, legend, orig_handle, xdescent, ydescent, width, height, fontsize, trans):
        return []


class HandlerLine2D(HandlerBase):
    def __init__(self, marker_pad=0.3, numpoints=None, **kwargs):
        super().__init__(**kwargs)
        self._marker_pad = marker_pad
        self._numpoints = numpoints


class HandlerPatch(HandlerBase):
    def __init__(self, patch_func=None, **kwargs):
        super().__init__(**kwargs)
        self._patch_func = patch_func


class HandlerLineCollection(HandlerBase):
    pass

class HandlerPathCollection(HandlerBase):
    pass

class HandlerRegularPolyCollection(HandlerBase):
    pass

class HandlerCircleCollection(HandlerBase):
    pass

class HandlerErrorbar(HandlerBase):
    pass

class HandlerStem(HandlerBase):
    pass

class HandlerTuple(HandlerBase):
    def __init__(self, ndivide=1, pad=None, **kwargs):
        super().__init__(**kwargs)
        self._ndivide = ndivide
        self._pad = pad
